SELECT id, departure_airport_code, arrival_airport_code, departure_airport_name, arrival_airport_name
FROM route
WHERE id = #{id}

SELECT id, departure_airport_code, arrival_airport_code, departure_airport_name, arrival_airport_name
FROM route
WHERE departure_airport_code = #{departureAirportCode} AND arrival_airport_code = #{arrivalAirportCode}

mapper.update:
UPDATE route
SET departure_airport_code = #{departureAirportCode},
    arrival_airport_code = #{arrivalAirportCode},
    departure_airport_name = #{departureAirportName},
    arrival_airport_name = #{arrivalAirportName}
WHERE id = #{id}
